_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv0 = vUv;
uv1 = vUv-.5;
float k = 16*lum(GetBlur1(vUvOriginal))*(3.14);

uv3 = multiply(uv1,mat2(cos(k),sin(k),-sin(k),cos(k)));
uvd = .25*lum(GetBlur1(vUvOriginal))*uv3;
vUv += uvd;
vec3 crisp = texture(sampler_fw_main,vUv);
vec2 diff = (vUv-vUvOriginal);
crisp = mix(crisp, GetPixel(vUvOriginal+2*diff), 0.5);

ret = crisp * (1-0.2*lum(GetBlur1(vUv)))- 0.1 *vRadius*vRadius;;
ret = ret*vec3(1,1,0) - 0.01;

vUv = uv1*uAspect.xy+0.5;
uv2 = vUv+noise(vUv/2)*0.07;
ret.b = exp(- 12*abs(0.3-uv2.x)) * (1-pow(uv1.y*2.5,2))*0.4;
ret.b *= 1+pow(texture(sampler_noise_lq,vUv*0.1+noise(uv2+uTime*.0019)*.004).r,3);

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv += vec2(q17,q18);
vUv = multiply((vUv-0.5)/uAspect.yx, mat2 (sin(q8),cos(q8),-cos(q8),sin(q8)))+q9;
uv1 = (vUv-0.5);
uvw = (uv1*uAspect.yx)*0.8+0.5;

wmask = (uvw.x<1) * (uvw.x>0)* (uvw.y<1) * (uvw.y>0);
tuv0 = vec2 (.5/length(uv1), aTan2(uv1.y,-uv1.x)) ;
near = sat (8*length(uv1))*0+1;
tuv = tuv0 + vec2(q19,0);

ftu = fract(tuv.y*tubes/2)-0.5;
nshape = clamp01(1-1/trad*pow(ftu,2));
tuv.x -= pow(nshape,0.2)*6*srad/tubes*tuv0.x;
mod = texture(sampler_pw_noise_lq,tuv.x*0.0002+rand_preset.z);
mod2= texture(sampler_pw_noise_lq,tuv.x*0.00007+rand_preset.y);

k1 = tuv.x*6*mod.x;
k2 = tuv.y*2*M_PI*tubes/2-4.7;
skym  = sat(sin(k2))*(sin(k1)+mod.y)*2;
skym1 = sat(sin(k2)+.4)*(sin(k1+fract(q19/8)*2*M_PI)+mod.y)*2 ;
skym1 = skym1 > .1+mod2.z;

k1 = abs(sin(tuv.x/tlen*M_PI*2*int(1+mod2.x*3.1)));
nshape *= sat(1.5*k1);
istube = sat (20*nshape-2);

vec2 sc = vec2(0.005,0.25*mod.z);
uv5  = tuv*vec2(0.25/tlen,tubes/16.0);
tuv += 0.25*int(8*skym)*!istube;
skym = sat (1+8*mod2.z-8*skym);
noise = near*!istube* (0.1+texture(sampler_pw_noise_lq,tuv*sc)-texture(sampler_pw_noise_lq,(tuv+0.003)*sc)*0.75).r;
col = (texture(sampler_pw_noise_lq,uv5/32)+0.1);

nshape2 = sat(q2+2*abs(sin(mod2.z*12*tan(ftu/srad)+q1*cos(q3*int(8*uv5.x)))));
neon = (0.3+nshape)*nshape2*istube*col;
neons= sat(k1)* clamp01(1-8/tubes*abs(ftu)) *col;

float dir = (int(uv5.y*16)%tubes)/2;
nmask = fract(((q4*uv5.x*8.0) *q20-q21)) < q22;
nmask *=  sat(q26*(tria((uv5.y*16.0+1)/q25+q27*2)-1)+1) ;

ret = (neon + neons*noise)* nmask*near*1.1;
uv2 = (uvw-0.5)*0.15+0.5;
lg = GetBlur1(fract(uv2))*vec3(1,1,0);
lg += lum(lg)+0.1;
ret += noise* lg*q11*near*!istube;

vec3 back = pow(vUv.x-0.2,3)*bcol+GetPixel(uvw).b*wmask*ocol;
ret = mix(ret, back, sat(1-10*length(uv1))) *skym;

ret += (GetPixel(uvw)+2*GetBlur2(uvw))*wmask*vec3(0.8,0.8,0);
stars = 0;
int n = 1, sanz = 4;
float t0 = q19*0.005;
while (n <= sanz) {
  float arg = (1.0*n/sanz-t0);
  float dist = fract(arg);
  float inten =  sat(1-dist);
  vec2 uv4 = 4*64 * dist* uv1;
  vec2 snoise = texture(sampler_pw_noise_lq,uv4/256);
  float smask = sat(1-snoise.x)*100+2;
  stars += (snoise.x>0.97)*inten* sat(1-2*pow(smask*length(fract(uv4)-0.5),2));
  stars += inten*sat(texture(sampler_noise_hq,uv4*0.002).r-0.8)*bcol;
n++;
}
ret = (ret)+(stars+back)*sat(1-4*skym*near);
//li =  sat (1.2-1*abs(-vUv.y+0.5)-2*vUv.x);
li = sat (1-2*abs(tuv0.y));
ret += li*near*noise*skym*skym1*(bcol+0.25) + nshape*0.05;

uv2 = fract(tuv0*vec2(0.003,tubes/2)+vec2(.51,0));
ret += GetBlur1(uv2)*vec3(1,1,0)*istube/2;
uv2 = fract(tuv0*vec2(0.05,3.5+0*tubes/2)+vec2(.15,0));
ret += GetBlur1(uv2).b*istube*ocol/4*sat (1-3*li);

ret += q12*exp(-6*length(0.5*tria(2*q10+tuv0.x*0+tuv0.y+texture(snh,tuv0.y)))) * (istube/4+!skym) * vec3 (0.25,0,0.5) ;

ret += vUv.x*0.02/length(fract(1.5*uv1-vec2(rand_preset.xy/2))-0.5)*!skym*bcol;
//ret = GetPixel(vUv).b;

  fragColor = ret;
}
